using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so keep the old name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|<key>", so keep the old format.
            entity.HasIdProperty(nameof(Blog.Id))
                  .HasIdJsonPropertyName("id");

            // Breaking change 3: EF 9 drops HasIndex for Cosmos (no longer supported).
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

